# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import boto3
import json

sns = boto3.client('sns')

def lambda_handler(event, context):
    try:
        topic_arn = event['topicArn']
        message = json.loads(event['message'])
        
        if 'type' in message and message['type'] == 'critical':
            sns.publish(
                TopicArn=topic_arn,
                Message=message['content'],
                Subject='Critical: ' + message['content']
            )
            print('Published critical notification')
        elif 'type' in message and message['type'] == 'info':
            sns.publish(
                TopicArn=topic_arn,
                Message=message['content'],
                Subject='Info: ' + message['content']
            )
            print('Published info notification')
        else:
            print('Invalid notification type')
            
    except Exception as e:
        print(e)